hooks.command:
node -e "
const p = process.env.CLAUDE_TOOL_INPUT_FILE_PATH || process.env.CLAUDE_TOOL_INPUT_PATH || '';
const skip = ['/test/', 'styles.js', 'main.jsx', '.test.', 'CLAUDE.md', 'settings.json', 'rounds.js'];
const isSrc = p.includes('/src/') && !skip.some(s => p.includes(s));
if (isSrc) {
  const test = p.replace(/\.(jsx?)$/, '.test.$1');
  console.error('[test-guard] ' + p + ' was modified — create or update ' + test + ' before finishing (see CLAUDE.md).');
}
"
